const cedula = $input.first().json.body.cedula;

return [{
  json: {
    cedula,
    query: `
      SELECT pc.codigo_cie10, pc.descripcion, pc.severidad,
             pc.activa, pc.fecha_dx, pc.notas
      FROM preexisting_conditions pc
      JOIN patients pt ON pt.id = pc.patient_id
      WHERE pt.cedula = '${cedula}'
        AND pc.activa = TRUE
    `
  }
}];

const cedula = $input.first().json.body.cedula;

return [{
  json: {
    cedula,
    query: `
      SELECT p.policy_number, p.estado, p.fecha_inicio, p.fecha_fin,
             p.consumido_anual, pl.nombre as plan, pl.cobertura_pct,
             pl.limite_anual, pl.deducible, pl.cubre_preexistencias,
             p.gestor_casos_email
      FROM policies p
      JOIN insured i ON i.id = p.insured_id
      JOIN plans pl ON pl.id = p.plan_id
      WHERE i.cedula = '${cedula}'
      LIMIT 1
    `
  }
}];

const raw = $input.first().json.content.parts[0].text;
const cleaned = raw.replace(/```json|```/g, '').trim();
const verdict = JSON.parse(cleaned);

// Escapar comillas simples para SQL
const escape = (str) => str ? str.replace(/'/g, "''") : null;

return [{
  json: {
    ...verdict,
    alerta: escape(verdict.alerta),
    mensaje_hospital: escape(verdict.mensaje_hospital),
    mensaje_gestor: escape(verdict.mensaje_gestor)
  }
}];
